/**
 * @param {unknown} value
 * @returns {boolean}
 */
function isPlainObject(value) {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

/**
 * List required field names that are missing or empty.
 * @param {Record<string, unknown>} record
 * @param {string[]} requiredFields
 * @returns {string[]}
 * @throws {TypeError} When record is not a plain object
 */
export function validateRequiredFields(record, requiredFields) {
  if (!isPlainObject(record)) {
    throw new TypeError('record must be a plain object');
  }

  const missing = [];
  for (const field of requiredFields) {
    const value = record[field];
    if (value === undefined || value === null || value === '') {
      missing.push(field);
    }
  }
  return missing;
}
